sql:
SELECT DISTINCT wc.wage_class_name
FROM wage_classes wc
INNER JOIN individuals i ON wc.wage_class_id = i.wage_class_id;

SELECT household_id
FROM households
ORDER BY household_id;

external_knowledge:
; Large households are defined as households with more than three members; 
; Management workclasses include jobs such as executives, managers, and other senior roles; 
; Average hours worked per week exceeding 40 indicates a full-time job or a job requiring long hours.
